import React, { useEffect, useState } from 'react'
import Header from './Header';
import { test_img } from '../assets/img';

export const Game = () => {
    const [imgWidth, setImgWidth] = useState(0)
    const [imgHeight, setImgHeight] = useState(0)

  return (
    <div className='flex flex-col h-screen'>
        <Header/>
        <div className='flex flex-1 w-full justify-center overflow-hidden'>
            <motion.img src={test_img} className='rounded-md h-full object-contain'
                    animate={{
                        x: [0, -5, 5, -5, 5, 0], // 左右抖动
                      }}
                      transition={{
                        duration: 0.3, // 持续时间
                        repeat: Infinity, // 无限重复
                        ease: "easeInOut",
                      }}
            onLoad={
                (e) => {
                    setImgWidth(e.currentTarget.width)
                    setImgHeight(e.currentTarget.height)
                }
            }
            />
        </div>

        <TextBox d_width={imgWidth} d_height={imgHeight} text={"Hmph! Took you long enough! Don’t get the wrong idea—I wasn’t waiting for you or anything… I just happened to be here, that’s all!"} speed={50}></TextBox>

    </div>
  )
}
const TextBox = ({d_height, d_width, name, text, speed}) => {

    const [currentText, setCurrentText] = useState("「」")    
    useEffect(() => {
        setCurrentText("")
        let index = 0;        
        const typingWord = setInterval(() => {
            if(index < text.length) {
                index++;
                // console.log(index);
                setCurrentText("「" + text.slice(0, index) + "」");
                // console.log(text.slice(0, index));
                // console.log(currentText)
            }         
        }, speed)

        return () => clearInterval(typingWord); 
    }, [speed, text])

    useEffect(() => {
        console.log("Updated currentText:", currentText);

    }, [currentText]);

    return (
        <div
        className='fixed bottom-0 left-1/2 -translate-x-1/2'
        style={{
            width: `${d_width}px`,
            height: `${d_height/3}px`
        }}
        >
            <span className='text-6xl absolute ml-8 mt-3 mr-8 text-white z-50'
            style={{
                textShadow: `
                -1px -1px 0 black,  
                1px -1px 0 black,  
                -1px  1px 0 black,  
                1px  1px 0 black,  
                -1px  0px 0 black,  
                1px  0px 0 black,  
                0px -1px 0 black,  
                0px  1px 0 black
            ` }}
            >
                ???
            </span>
            <span className='text-4xl absolute ml-8 mt-24 mr-8 text-white z-50'
            style={{
                textShadow: `
                -1px -1px 0 black,  
                1px -1px 0 black,  
                -1px  1px 0 black,  
                1px  1px 0 black,  
                -1px  0px 0 black,  
                1px  0px 0 black,  
                0px -1px 0 black,  
                0px  1px 0 black
            ` }}
            >{currentText}</span>
            <div className="w-full h-full relative bg-[rgba(128,128,255,0.5)] blur-md"/>

        </div>
    )
}

export default Game;
